<template >
  <div class="container my-3 animate__animated animate__fadeIn">
    <div class="row">
        <div class="col-12 col-md-12">
            <div class="card">
                <div class="accordion" id="accordionExample">
                <div class="accordion-item">
                    <h2 class="accordion-header ">
                    <button class="d-grid accordion-button  text-center" type="button" data-bs-toggle="collapse" data-bs-target="#collapseOne" aria-expanded="true" aria-controls="collapseOne">
                            <span><h3>合計 {{ totalPrice }} 元</h3></span>
                            <span><h3>購物車共 {{ cartItemsCount }} 件商品</h3></span>
                    </button>
                    </h2>
                    <div id="collapseOne" class="accordion-collapse collapse show" data-bs-parent="#accordionExample">
                        <div class="accordion-body">
                            <div class="table-responsive-md">
                                <table class="table align-middle text-center">
                                    <thead >
                                        <tr class="d-none d-md-table-row text-start">
                                            <th colspan="2">商品資料</th>
                                            <th >單件價格</th>
                                            <th >數量</th>
                                            <th >小計</th>
                                        </tr>
                                    </thead>
                                    <tbody>    
                                            <tr  v-for="item in items" :key="item.id" class="text-start">
                                                <td class="w-25 h-25"><img class="img-fluid w-100 h-100" :src="item.productImg"  style="min-width: 60px; min-height: 60px;"></td>
                                                <td>{{ item.productName }}</td>
                                                <td >{{ item.productPrice }}</td>
                                                <td>{{item.quantity}}</td>
                                                <td>{{ item.productPrice * item.quantity }}</td>
                                            </tr>                            
                                    </tbody>
                                </table>
                            </div>    
                        </div>
                    </div>
                </div>
                </div>
            </div>
        </div>
    </div>
  </div>
  <div class="container my-3 animate__animated animate__fadeIn">
    <div class="row">
        <div class="col-12 col-md-6">
            <div class="card p-1">
                <table class="table">
                    <thead>
                        <tr >
                            <th ><h4>顧客資料</h4></th>
                        </tr>
                    </thead>
                </table>
                <div class="p-2">
                    <div class="mb-3">
                        <label for="fullName" class="form-label">顧客姓名：</label>
                        <input type="text" class="form-control" id="fullName" v-model="userInfo.fullName">
                    </div>
                    <div class="mb-3">
                        Email：
                        <input type="email" class="form-control" id="email" v-model="userInfo.email" disabled>
                    </div>
                    <div class="mb-3">
                        <label for="phoneNumber" class="form-label">手機號碼：</label>
                        <input type="text" class="form-control" id="phoneNumber" v-model="userInfo.phoneNumber">
                    </div>
                </div>

            </div>
            <div class="row  my-4 ">
                <div class="col-12 col-md-12">
                    <div class="card p-1">
                        <table class="table">
                            <thead>
                                <tr >
                                    <th ><h4>訂單備註</h4></th>
                                </tr>
                            </thead>
                        </table>
                        <div class=" p-2">
                            <label for="phoneNumber" class="form-label">留下想說的話：</label>
                            <textarea class="form-control" id="exampleFormControlTextarea1" rows="3"></textarea>
                        </div>
                    </div>
                </div>
            </div>
        </div>
        <div class="col-12 col-md-6">
            <div class="card p-1">
                <table class="table">
                    <thead>
                        <tr >
                            <th ><h4>送貨資料</h4></th>
                        </tr>
                    </thead>
                </table>
                <div class="p-2">
                    <div class="my-3">您選擇的支付方式：{{ paymentStatus.payMethod  }}</div>
                    <div class="my-3">您選擇的送貨方式：{{ paymentStatus.deliveryMethod  }}</div>
                    <div class="form-check mb-3">
                        <input class="form-check-input" type="checkbox" v-model="isChecked" id="flexCheckChecked" checked>
                        <label class="form-check-label" for="flexCheckChecked">
                            收件人資料與顧客資料相同
                        </label>
                    </div>
                    <div class="mb-3">
                        <label for="deliveryFullName" class="form-label">收件者姓名：</label>
                        <input type="text" class="form-control" id="deliveryFullName" v-model="deliveryInfo.deliFullName">
                    </div>
                    <div class="mb-3">
                        <label for="deliveryPhoneNumber" class="form-label">手機號碼：</label>
                        <input type="text" class="form-control" id="deliveryPhoneNumber" v-model="deliveryInfo.deliPhoneNumber">
                    </div>
                    <div class="mb-3">
                        <label for="deliveryAddress" class="form-label">配送地址：</label>
                        <input type="text" class="form-control" id="deliveryAddress" v-model="deliveryInfo.deliAddress">
                    </div>
                    
                    <button @click="submitOrder"  id="submitbtn"  class="w-100  btn btn-success btn-gradient text-center ">
                        <template v-if="!submiting">
                            提交訂單
                        </template>
                        <template v-if="submiting">
                            <div class="spinner-border spinner-border-sm" role="status">
                                 <span class="visually-hidden ">Loading...</span>
                            </div>
                        </template>
                        
                    </button>
                    <div v-if="submitSuccess" class="alert alert-success mt-3 animate__animated animate__fadeIn" role="alert">
                       訂單提交成功！2秒後將自動跳轉頁面... <router-link to="/memberpage/orders">查看訂單</router-link>
                    </div>
                    <div v-if="submiterror" class="alert alert-danger mt-3" role="alert">
                        請正確填寫配送資訊!
                    </div>
                </div>
            </div>
        </div>
    </div>
    

  </div>
  
</template>

<script>
import {reactive,toRefs,computed,onMounted,ref,watch,toRaw} from 'vue'
import axios from 'axios'
import {useRouter} from 'vue-router'
import {usePaymentStatusStore} from '@/store/paymentStatus'
import { useCartItemsStore } from '@/store/cartItems'

export default {
  name:'CheckOut',
  setup(){
    let carItemsStore=useCartItemsStore()
    const router= useRouter()
    let cartItems =reactive(JSON.parse(localStorage.getItem('cart')))
    let totalPrice =computed(()=>{
        let temp=0
        for(var i=0;i<cartItems.items.length;i++){
            temp+=cartItems.items[i].quantity * cartItems.items[i].productPrice
        }
        return temp
    })
    let paymentStatus=usePaymentStatusStore().paymentStatus

    let cartItemsCount=computed(()=>{
        return cartItems.items.length
    })
    let userInfo =reactive({
        fullName:'',
        address:'',
        phoneNumber:'',
        email:'',
        id:''
    })
    let deliveryInfo = reactive({
        deliFullName:'',
        deliAddress:'',
        deliPhoneNumber:'',
        customId:'',
        totalAmount:totalPrice.value,
        payMethod:paymentStatus.payMethod,
        deliveryMethod:paymentStatus.deliveryMethod,
        deliveryStatus:0
    })
    let submiterror=ref(false)
    let submiting =ref(false)
    let submitSuccess=ref(false)
    let isChecked=ref(false)
    watch(isChecked,()=>{
        if(isChecked.value){
            deliveryInfo.deliFullName=userInfo.fullName
            deliveryInfo.deliAddress=userInfo.address
            deliveryInfo.deliPhoneNumber=userInfo.phoneNumber
        }
        
    },{deep:true})

    onMounted(()=>{
        let userId =localStorage.getItem('isLogin')
        axios.get(`/userinfo?account=${userId}`).then(
            response =>{
               let data =response.data
               userInfo.fullName=data.fullName
               userInfo.phoneNumber='0'+data.phoneNumber
               userInfo.email=data.email
               userInfo.address=data.address
               userInfo.id=data.id
               deliveryInfo.customId=userInfo.id
               deliveryInfo.deliEmail=userInfo.email
               if(deliveryInfo.payMethod ===''|| deliveryInfo.deliveryMethod === ''){
                    router.push('/')
               }
            }
        ).catch(
            error =>{
                console.log(error.message)
            }
        )
    })
    
    function submitOrder(){
        for(var i in deliveryInfo){
            if(deliveryInfo[i]===null || deliveryInfo[i] === ''){
                submiterror.value=true
                return
            }else{
                submiterror.value=false
            }

            
        }
        
        this.submiting=true
        

        const  jsonDeliveryInfo =toRaw(deliveryInfo)
        const  jsonCartItems=toRaw(cartItems.items)
        const requestData={jsonDeliveryInfo,jsonCartItems}
        const btn =document.getElementById('submitbtn')
        btn.setAttribute("disabled","true")
        axios.post('/submitorder',requestData,{ headers: { 'Content-Type': 'application/json' } }).then(
            () =>{
                
                this.submiting=false
                this.submitSuccess=true
                localStorage.setItem('cart',JSON.stringify({items:[]}))
                setTimeout(() => {
                    carItemsStore.cartTrigger()
                    router.push('/memberpage/orders')
                 }, 2000);
            }
        ).catch(
            error =>{
                console.log(error.message)
                btn.removeAttribute('disabled')
            }
        )

    }

    return{
        ...toRefs(cartItems),
        totalPrice,
        cartItemsCount,
        userInfo,
        deliveryInfo,
        isChecked,
        submiting,
        submitOrder,
        submitSuccess,
        submiterror,
        paymentStatus
        
    }
  }
}
</script>

